var lengthOfLongestSubstring = function(s) {
    const last = new Map();
    let start = 0, best = 0;
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (last.has(c) && last.get(c) >= start) {
            start = last.get(c) + 1;
        }
        last.set(c, i);
        best = Math.max(best, i - start + 1);
    }
    return best;
};
